SELECT translator_specialization, translator_experience, COUNT(*) AS translator_count
FROM translators
GROUP BY translator_specialization, translator_experience;

SELECT 
    CAST(SUM(CASE WHEN untranslated = 0 AND needs_review = 0 THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS completion_rate
FROM translations;

SELECT change_date, change_description
FROM translation_history
WHERE change_type = 'update';

SELECT name
FROM translators
WHERE translator_experience = (SELECT MAX(translator_experience) FROM translators);
